const i = items[0].json;
if (!i.system_prompt || !i.user_payload) {
  throw new Error('system_prompt and user_payload are required');
}
const model = i.model || $env.LLM_MODEL || 'gpt-4o';
const temperature = i.temperature != null ? Number(i.temperature) : 0.3;
return [{
  json: {
    model,
    temperature,
    system_prompt: i.system_prompt,
    user_content: typeof i.user_payload === 'string' ? i.user_payload : JSON.stringify(i.user_payload),
    meta: i.meta || {}
  }
}];

const resp = items[0].json;
const statusCode = resp.statusCode || resp.status || 200;
const body = resp.body || resp;
const meta = $('Prep Request').item.json.meta || {};

if (statusCode === 429) {
  return [{ json: { ok: false, retryable: true, statusCode: 429, error: 'rate_limited', meta } }];
}
if (statusCode >= 400) {
  return [{ json: { ok: false, retryable: statusCode >= 500, statusCode, error: body.error?.message || body.message || JSON.stringify(body).slice(0, 400), meta } }];
}

let raw = body.choices?.[0]?.message?.content || body.message?.content || '';
let text = String(raw).trim();
if (text.startsWith('```')) {
  text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
}
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  return [{ json: { ok: false, retryable: false, statusCode: 200, error: 'invalid_json: ' + e.message, raw: text.slice(0, 500), meta } }];
}
return [{ json: { ok: true, data: parsed, raw_text: text, meta, usage: body.usage || null } }];
